function solve(edges, online, k) {
    const n = online.length;
    const graph = new Map();

    // Build the graph
    for (const [u, v, cost] of edges) {
        if (!graph.has(u)) {
            graph.set(u, []);
        }
        graph.get(u).push({ node: v, cost });
    }

    // Use a priority queue for Dijkstra-like approach
    const pq = new PriorityQueue((a, b) => b.cost - a.cost);

    // Start from node 0
    pq.enqueue({ node: 0, totalCost: 0, minEdgeCost: Infinity });

    while (!pq.isEmpty()) {
        const { node, totalCost, minEdgeCost } = pq.dequeue();

        // If we reached the destination
        if (node === n - 1) {
            return minEdgeCost;
        }

        // Skip if node is offline
        if (!online[node]) {
            continue;
        }

        // Explore neighbors
        if (graph.has(node)) {
            for (const { node: neighbor, cost } of graph.get(node)) {
                // Skip if neighbor is offline
                if (!online[neighbor]) {
                    continue;
                }

                // Calculate new total cost and new min edge cost
                const newTotalCost = totalCost + cost;
                const newMinEdgeCost = Math.min(minEdgeCost, cost);

                // If total cost is within k, add to the priority queue
                if (newTotalCost <= k) {
                    pq.enqueue({ node: neighbor, totalCost: newTotalCost, minEdgeCost: newMinEdgeCost });
                }
            }
        }
    }

    // No valid path found
    return -1;
}

class PriorityQueue {
    constructor(compare) {
        this.compare = compare;
        this.heap = [];
    }

    enqueue(item) {
        this.heap.push(item);
        this.heapifyUp(this.heap.length - 1);
    }

    dequeue() {
        if (this.heap.length === 0) return null;
        const result = this.heap[0];
        this.heap[0] = this.heap.pop();
        this.heapifyDown(0);
        return result;
    }

    isEmpty() {
        return this.heap.length === 0;
    }

    heapifyUp(index) {
        while (index > 0) {
            const parentIndex = Math.floor((index - 1) / 2);
            if (this.compare(this.heap[index], this.heap[parentIndex]) >= 0) {
                [this.heap[index], this.heap[parentIndex]] = [this.heap[parentIndex], this.heap[index]];
                index = parentIndex;
            } else {
                break;
            }
        }
    }

    heapifyDown(index) {
        const leftChild = 2 * index + 1;
        const rightChild = 2 * index + 2;
        let smallest = index;

        if (leftChild < this.heap.length && this.compare(this.heap[leftChild], this.heap[smallest]) < 0) {
            smallest = leftChild;
        }

        if (rightChild < this.heap.length && this.compare(this.heap[rightChild], this.heap[smallest]) < 0) {
            smallest = rightChild;
        }

        if (smallest !== index) {
            [this.heap[index], this.heap[smallest]] = [this.heap[smallest], this.heap[index]];
            this.heapifyDown(smallest);
        }
    }
}

