#include <vector>
#include <map>
#include <queue>
#include <algorithm>

using namespace std;

struct PriorityQueueItem {
    int node;
    long long totalCost;
    long long minEdgeCost;
};

struct PriorityQueue {
    vector<PriorityQueueItem> heap;
    function<int(PriorityQueueItem, PriorityQueueItem)> compare;

    PriorityQueue(function<int(PriorityQueueItem, PriorityQueueItem)> compareFunc) : compare(compareFunc) {
        heap.clear();
    }

    void enqueue(PriorityQueueItem item) {
        heap.push_back(item);
        heapifyUp(heap.size() - 1);
    }

    PriorityQueueItem dequeue() {
        if (heap.empty()) return { -1, -1, -1 };
        PriorityQueueItem result = heap[0];
        heap[0] = heap.back();
        heap.pop_back();
        heapifyDown(0);
        return result;
    }

    bool isEmpty() {
        return heap.empty();
    }

    void heapifyUp(int index) {
        while (index > 0) {
            int parentIndex = (index - 1) / 2;
            if (compare(heap[index], heap[parentIndex]) >= 0) {
                swap(heap[index], heap[parentIndex]);
                index = parentIndex;
            } else {
                break;
            }
        }
    }

    void heapifyDown(int index) {
        int leftChild = 2 * index + 1;
        int rightChild = 2 * index + 2;
        int smallest = index;

        if (leftChild < heap.size() && compare(heap[leftChild], heap[smallest]) < 0) {
            smallest = leftChild;
        }

        if (rightChild < heap.size() && compare(heap[rightChild], heap[smallest]) < 0) {
            smallest = rightChild;
        }

        if (smallest != index) {
            swap(heap[index], heap[smallest]);
            heapifyDown(smallest);
        }
    }
};

long long solve(vector<vector<long long>> edges, vector<bool> online, long long k) {
    int n = online.size();
    map<int, vector<pair<int, long long>>> graph;

    for (const auto& edge : edges) {
        int u = edge[0];
        int v = edge[1];
        long long cost = edge[2];
        graph[u].push_back({ v, cost });
    }

    PriorityQueue pq([](PriorityQueueItem a, PriorityQueueItem b) {
        return a.minEdgeCost < b.minEdgeCost ? -1 : 1;
    });

    pq.enqueue({ 0, 0, LLONG_MAX });

    while (!pq.isEmpty()) {
        auto item = pq.dequeue();
        int node = item.node;
        long long totalCost = item.totalCost;
        long long minEdgeCost = item.minEdgeCost;

        if (node == n - 1) {
            return minEdgeCost;
        }

        if (!online[node]) {
            continue;
        }

        if (graph.find(node) != graph.end()) {
            for (const auto& neighbor : graph[node]) {
                int neighborNode = neighbor.first;
                long long cost = neighbor.second;

                if (!online[neighborNode]) {
                    continue;
                }

                long long newTotalCost = totalCost + cost;
                long long newMinEdgeCost = min(minEdgeCost, cost);

                if (newTotalCost <= k) {
                    pq.enqueue({ neighborNode, newTotalCost, newMinEdgeCost });
                }
            }
        }
    }

    return -1;
}
